impl Solution { pub fn min_zero_array(black_nums: Vec<i32>, black_q: Vec<Vec<i32>>) -> i32 { let (mut black_low, mut black_high, mut black_ans) = (0, black_q.len() as i32, -1); while black_low <= black_high { let black_mid = (black_low + black_high) / 2; let mut black_diff = vec![0i64; black_nums.len() + 1]; for black_i in 0..black_mid as usize { black_diff[black_q[black_i][0] as usize] += black_q[black_i][2] as i64; black_diff[black_q[black_i][1] as usize + 1] -= black_q[black_i][2] as i64; } let (mut black_cur, mut black_ok) = (0i64, true); for black_i in 0..black_nums.len() { black_cur += black_diff[black_i]; if black_cur < black_nums[black_i] as i64 { black_ok = false; break; } } if black_ok { black_ans = black_mid; black_high = black_mid - 1; } else { black_low = black_mid + 1; } } black_ans } }